const sources = [
  ...($('📡 MIT Tech Review').all()[0]?.json?.items || []),
  ...($('📡 Import AI').all()[0]?.json?.items || []),
  ...($('📡 CNIL').all()[0]?.json?.items || [])
];

const articles = sources.slice(0, 10).map(item => ({
  title: item.title,
  summary: item.description?.replace(/<[^>]*>/g, '').slice(0, 300),
  link: item.link,
  source: item.author || 'Source inconnue',
  date: item.pubDate
}));

const prompt = `Tu es l'assistant de Gilles Anselme, fondateur de Neobik, expert IA basé en Guadeloupe.

Gilles écrit une newsletter hebdomadaire sur l'IA pour des entrepreneurs et dirigeants des Antilles-Guyane.
Son ton : lucide, direct, sans jargon, humain. Il challenge les idées reçues sur l'IA.

Voici les articles de la semaine :\n${articles.map((a, i) => `${i+1}. ${a.title}\n${a.summary}\nLien : ${a.link}`).join('\n\n')}

Rédige un draft de newsletter avec :
- Un titre accrocheur (pas de clickbait)
- Une intro personnelle de 2-3 phrases (style Gilles, ton observateur critique)
- 3-4 résumés commentés des articles les plus pertinents pour les entrepreneurs antillais (50-80 mots chacun)
- Une question de réflexion finale
- Un CTA discret vers neobik.com

Format : HTML simple. Langue : français. Longueur totale : 400-600 mots.
NE PAS inventer de faits. Si un article n'est pas clair, dis-le.`;

return [{ json: { prompt, articlesCount: articles.length } }];

const response = $json;
const content = response.content?.[0]?.text || 'Erreur : pas de contenu généré';
const week = new Date().toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' });

return [{ json: { subject: `[DRAFT] Newsletter Neobik — ${week}`, body: content, week } }];
